class Solution {
public:
    long long smallestNumber(long long num) {
        std::vector<int> digits;
        while (num != 0) {
            digits.push_back(num % 10);
            num /= 10;
        }
        std::sort(digits.begin(), digits.end());
        long long result = 0;
        for (int i = 0; i < digits.size(); ++i) {
            result = result * 10 + digits[i];
        }
        return result;
    }
};
```

